class Node {
  constructor(val) { this.val = val; this.next = null; }
}
class Stack {
  constructor() { this.top = null; this.size = 0; }
  push(val) {
    const node = new Node(val);
    node.next = this.top;
    this.top = node;
    this.size++;
  }
  pop() {
    if (!this.top) return null;
    const val = this.top.val;
    this.top = this.top.next;
    this.size--;
    return val;
  }
  peek() { return this.top ? this.top.val : null; }
  isEmpty() { return this.size === 0; }
}

class Graph {
  constructor() { this.adjacencyList = new Map(); }
  addVertex(v) { if (!this.adjacencyList.has(v)) this.adjacencyList.set(v, []); }
  addEdge(v1, v2) {
    this.adjacencyList.get(v1).push(v2);
    this.adjacencyList.get(v2).push(v1);
  }
  bfs(start) {
    const visited = new Set([start]);
    const queue = [start];
    const result = [];
    while (queue.length) {
      const vertex = queue.shift();
      result.push(vertex);
      for (const neighbor of this.adjacencyList.get(vertex))
        if (!visited.has(neighbor)) { visited.add(neighbor); queue.push(neighbor); }
    }
    return result;
  }
}

function diameterOfBinaryTree(root) {
  let diameter = 0;
  function height(node) {
    if (!node) return 0;
    const left = height(node.left);
    const right = height(node.right);
    diameter = Math.max(diameter, left + right);
    return 1 + Math.max(left, right);
  }
  height(root);
  return diameter;
}

function isSymmetric(root) {
  function isMirror(t1, t2) {
    if (!t1 && !t2) return true;
    if (!t1 || !t2) return false;
    return t1.val === t2.val && isMirror(t1.left, t2.right) && isMirror(t1.right, t2.left);
  }
  return isMirror(root, root);
}

function quickSort(arr, lo = 0, hi = arr.length - 1) {
  if (lo < hi) {
    const pivot = partition(arr, lo, hi);
    quickSort(arr, lo, pivot - 1);
    quickSort(arr, pivot + 1, hi);
  }
  return arr;
}
function partition(arr, lo, hi) {
  const pivot = arr[hi];
  let i = lo;
  for (let j = lo; j < hi; j++)
    if (arr[j] < pivot) { [arr[i], arr[j]] = [arr[j], arr[i]]; i++; }
  [arr[i], arr[hi]] = [arr[hi], arr[i]];
  return i;
}

function maxArea(height) {
  let left = 0, right = height.length - 1, max = 0;
  while (left < right) {
    const area = Math.min(height[left], height[right]) * (right - left);
    max = Math.max(max, area);
    if (height[left] < height[right]) left++;
    else right--;
  }
  return max;
}

function findMin(nums) {
  let lo = 0, hi = nums.length - 1;
  while (lo < hi) {
    const mid = Math.floor((lo + hi) / 2);
    if (nums[mid] > nums[hi]) lo = mid + 1;
    else hi = mid;
  }
  return nums[lo];
}

function search(nums, target) {
  let lo = 0, hi = nums.length - 1;
  while (lo <= hi) {
    const mid = Math.floor((lo + hi) / 2);
    if (nums[mid] === target) return mid;
    if (nums[lo] <= nums[mid]) {
      if (target >= nums[lo] && target < nums[mid]) hi = mid - 1;
      else lo = mid + 1;
    } else {
      if (target > nums[mid] && target <= nums[hi]) lo = mid + 1;
      else hi = mid - 1;
    }
  }
  return -1;
}

function isValidSudoku(board) {
  const rows = Array.from({length: 9}, () => new Set());
  const cols = Array.from({length: 9}, () => new Set());
  const boxes = Array.from({length: 9}, () => new Set());
  for (let r = 0; r < 9; r++) {
    for (let c = 0; c < 9; c++) {
      const val = board[r][c];
      if (val === '.') continue;
      const box = Math.floor(r/3) * 3 + Math.floor(c/3);
      if (rows[r].has(val) || cols[c].has(val) || boxes[box].has(val)) return false;
      rows[r].add(val); cols[c].add(val); boxes[box].add(val);
    }
  }
  return true;
}

function flatten(arr) {
  const result = [];
  const stack = [...arr];
  while (stack.length) {
    const item = stack.pop();
    if (Array.isArray(item)) stack.push(...item);
    else result.unshift(item);
  }
  return result;
}

