class HashMap {
  constructor(size = 53) {
    this.buckets = new Array(size);
    this.size = size;
  }
  _hash(key) {
    let hash = 0;
    for (const ch of String(key)) hash = (hash * 31 + ch.charCodeAt(0)) % this.size;
    return hash;
  }
  put(key, value) {
    const idx = this._hash(key);
    if (!this.buckets[idx]) this.buckets[idx] = [];
    const existing = this.buckets[idx].find(p => p[0] === key);
    if (existing) existing[1] = value;
    else this.buckets[idx].push([key, value]);
  }
  get(key) {
    const bucket = this.buckets[this._hash(key)];
    const pair = bucket && bucket.find(p => p[0] === key);
    return pair ? pair[1] : undefined;
  }
  remove(key) {
    const idx = this._hash(key);
    const bucket = this.buckets[idx];
    if (bucket) this.buckets[idx] = bucket.filter(p => p[0] !== key);
  }
}

function subsets(nums) {
  const result = [[]];
  for (const num of nums) {
    const len = result.length;
    for (let i = 0; i < len; i++) {
      result.push([...result[i], num]);
    }
  }
  return result;
}
